import urllib.request, re; content = urllib.request.urlopen(urllib.request.Request("https://www.comicxia.com/categories", headers={"User-Agent":"Mozilla"})).read().decode(); print("CATEGORIES:", re.search(r"\"categories\":\[(.*?)\]", content).group(1)[:200]); print("REGIONS:", re.search(r"\"regions\":\[(.*?)\]", content).group(1)[:200]); print("STATUS:", re.search(r"\"status\":\[(.*?)\]", content).group(1)[:200])
